# 1. 月次データ CSV (Day 3 /xlsx 用)
# =============================================================================

def build_csv():
    """
    2025年11月〜2026年4月の月次データ。
    傾向：食品=成長、日用品=横ばい、オフィス用品=縮小。
    """
    months = [
        "2025-11", "2025-12", "2026-01", "2026-02", "2026-03", "2026-04",
    ]
    # 売上(千円), 粗利率, 案件数, 新規顧客, アクティブ顧客
    division_data = {
        "食品事業部":     [(132000, 0.182,  87, 12, 245),
                          (138500, 0.185,  91, 14, 248),
                          (135200, 0.181,  85, 11, 251),
                          (141000, 0.190,  93, 16, 257),
                          (143800, 0.188,  95, 13, 262),
                          (146500, 0.193,  98, 17, 268)],
        "日用品事業部":   [( 91500, 0.225,  64,  6, 178),
                          ( 93000, 0.221,  66,  8, 180),
                          ( 90200, 0.230,  62,  5, 178),
                          ( 89500, 0.228,  61,  4, 176),
                          ( 92800, 0.232,  65,  7, 179),
                          ( 89800, 0.224,  63,  6, 177)],
        "オフィス用品事業部": [( 62800, 0.248,  41,  3, 134),
                              ( 60100, 0.241,  39,  2, 132),
                              ( 58400, 0.236,  37,  3, 128),
                              ( 56200, 0.229,  35,  2, 124),
                              ( 54800, 0.222,  33,  1, 121),
                              ( 52600, 0.218,  31,  2, 117)],
    }

    out = os.path.join(OUT_DIR, "サンプル商事_月次データ_2025-11_2026-04.csv")
    with open(out, "w", encoding="utf-8-sig", newline="") as f:
        w = csv.writer(f)
        w.writerow([
            "年月", "事業部", "売上(千円)", "売上原価(千円)", "粗利(千円)",
            "粗利率", "案件数", "新規顧客数", "アクティブ顧客数",
        ])
        for div, rows in division_data.items():
            for m, (rev, gpm, deals, new_c, active_c) in zip(months, rows):
                cogs = round(rev * (1 - gpm))
                gp = rev - cogs
                w.writerow([m, div, rev, cogs, gp, f"{gpm*100:.1f}%",
                            deals, new_c, active_c])
    return out


