def build_readme():
    out = os.path.join(OUT_DIR, "README.txt")
    # utf-8-sig (BOM付き) でメモ帳等でも文字化けしない
    with open(out, "w", encoding="utf-8-sig") as f:
        f.write(README_TEXT)
    return out


